const KIE_API_BASE = "https://api.kie.ai";
const KIE_UPLOAD_BASE = "https://kieai.redpandaai.co";

function getKieApiKey() {
    const key = process.env.KIE_API_KEY;
    if (!key) {
        throw new Error("Missing KIE_API_KEY in .env");
    }
    return key;
}

async function sleep(ms: number) {
    return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function uploadReferenceFilesToKie(files: File[]) {
    const apiKey = getKieApiKey();
    const uploaded: Array<{
        filePath: string;
        originalName: string;
        mimeType: string | null;
    }> = [];

    for (const file of files) {
        if (!(file instanceof File) || file.size === 0) continue;

        const form = new FormData();
        form.set("file", file, file.name);
        form.set("uploadPath", "images/user-uploads");
        form.set("fileName", file.name);

        const res = await fetch(`${KIE_UPLOAD_BASE}/api/file-stream-upload`, {
            method: "POST",
            headers: {
                Authorization: `Bearer ${apiKey}`,
            },
            body: form,
        });

        const json = await res.json();

        if (!res.ok || json?.code !== 200 || !json?.data?.downloadUrl) {
            throw new Error(`Kie file upload failed: ${JSON.stringify(json)}`);
        }

        uploaded.push({
            filePath: json.data.downloadUrl,
            originalName: json.data.originalName || file.name,
            mimeType: json.data.mimeType || file.type || null,
        });
    }

    return uploaded;
}

export async function generateImageWithKie(
    prompt: string,
    referenceImages: string[] = []
) {
    const apiKey = getKieApiKey();

    const createRes = await fetch(`${KIE_API_BASE}/api/v1/jobs/createTask`, {
        method: "POST",
        headers: {
            Authorization: `Bearer ${apiKey}`,
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            model: "nano-banana-2",
            input: {
                prompt,
                image_input: referenceImages,
                google_search: true,
                aspect_ratio: "auto",
                resolution: "1K",
                output_format: "png",
            },
        }),
    });

    const createJson = await createRes.json();

    if (!createRes.ok || createJson?.code !== 200 || !createJson?.data?.taskId) {
        throw new Error(
            `Kie task creation failed: ${JSON.stringify(createJson)}`
        );
    }

    const taskId = createJson.data.taskId;

    for (let attempt = 0; attempt < 30; attempt++) {
        await sleep(3000);

        const statusRes = await fetch(
            `${KIE_API_BASE}/api/v1/jobs/recordInfo?taskId=${encodeURIComponent(taskId)}`,
            {
                method: "GET",
                headers: {
                    Authorization: `Bearer ${apiKey}`,
                },
            }
        );

        const statusJson = await statusRes.json();

        if (!statusRes.ok || statusJson?.code !== 200) {
            throw new Error(
                `Kie status check failed: ${JSON.stringify(statusJson)}`
            );
        }

        const data = statusJson.data;
        const state = data?.state;

        if (state === "success") {
            let parsedResult: unknown = data?.resultJson;

            if (typeof parsedResult === "string") {
                try {
                    parsedResult = JSON.parse(parsedResult);
                } catch { }
            }

            return {
                taskId,
                state,
                raw: statusJson,
                result: parsedResult,
            };
        }

        if (state === "fail") {
            throw new Error(
                `Kie generation failed: ${data?.failMsg || "Unknown failure"}`
            );
        }
    }

    throw new Error("Kie generation timed out.");
}