function tryParseJson(value: string | null) {
    if (!value) return null;

    try {
        return JSON.parse(value);
    } catch {
        return null;
    }
}

function stripHtml(html: string) {
    return html
        .replace(/<script[\s\S]*?<\/script>/gi, "")
        .replace(/<style[\s\S]*?<\/style>/gi, "")
        .replace(/<[^>]+>/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function extractImageUrlsFromResult(result: unknown): string[] {
    const urls = new Set<string>();

    function walk(value: unknown) {
        if (!value) return;

        if (typeof value === "string") {
            const lower = value.toLowerCase();

            if (
                (value.startsWith("http://") || value.startsWith("https://")) &&
                (lower.includes(".png") ||
                    lower.includes(".jpg") ||
                    lower.includes(".jpeg") ||
                    lower.includes(".webp") ||
                    lower.includes("image"))
            ) {
                urls.add(value);
            }

            return;
        }

        if (Array.isArray(value)) {
            for (const item of value) walk(item);
            return;
        }

        if (typeof value === "object") {
            for (const nested of Object.values(value as Record<string, unknown>)) {
                walk(nested);
            }
        }
    }

    walk(result);
    return Array.from(urls);
}

async function scrapeAndGenerateAds(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    if (!jobId) throw new Error("Missing jobId");

    const job = await prisma.job.findUnique({
        where: { id: jobId },
    });

    if (!job) throw new Error("Job not found");

    const requestedCount = normalizeRequestedAdCount(job.numberOfAds);

    try {
        // 1) Scrape saved job URL
        const scraped = await scrapeUrlToHtml(job.url);
        const rawText = stripHtml(scraped.html).slice(0, 15000);

        if (!rawText.trim()) {
            throw new Error("Scrape produced empty text.");
        }

        // 2) Single practical generation step:
        // scraped content + memory context + form settings -> final ad tabs
        const effectiveCampaignType: "product" | "donation" =
            job.campaignType === "donation" ? "donation" : "product";

        const claudeOutput = await analyzeWebsiteText({
            rawText,
            campaignType: effectiveCampaignType,
            platform: job.platform || "Meta",
            funnelStage: job.funnelStage || "Mix",
            formatRatio: job.formatRatio || "70% 9:16 / 30% 1080x1080",
            primaryAngles:
                job.primaryAngles || "Problem/Solution, Lifestyle, Urgency",
            testimonialUsage: job.testimonialUsage || "Mix",
            ctaStyle: job.ctaStyle || "Mix",
            visualStyle: job.visualStyle || "Mix",
            numberOfAds: String(requestedCount),
            referenceImageTypes: job.referenceImageTypes || "Product only",
        });

        const parsedAdsResult = parseValidateAndNormalizeClaudeAds(
            claudeOutput,
            requestedCount
        );

        const diagnostics: ClaudeParseDiagnostics = parsedAdsResult.diagnostics;
        const diagJson = JSON.stringify(diagnostics, null, 2);

        if (!parsedAdsResult.ok) {
            await prisma.job.update({
                where: { id: jobId },
                data: {
                    status: "error",
                    rawText,
                    claudeOutput: `${claudeOutput || ""}

__CLAUDE_PARSE_DIAGNOSTICS__
${diagJson}
__END_CLAUDE_PARSE_DIAGNOSTICS__`,
                    kieResult: null,
                },
            });

            redirect(`/jobs/${jobId}`);
        }

        // 3) Persist shared reference images for Kie
        const uniqueImageUrls = Array.from(
            new Set((scraped.imageUrls || []).filter(Boolean))
        ).slice(0, 25);

        await prisma.referenceAsset.deleteMany({
            where: { jobId, adId: null },
        });

        if (uniqueImageUrls.length > 0) {
            await prisma.referenceAsset.createMany({
                data: uniqueImageUrls.map((url, index) => ({
                    jobId,
                    adId: null,
                    filePath: url,
                    originalName: `scraped-image-${index + 1}`,
                    mimeType: null,
                })),
            });
        }

        // 4) Persist ads (tabs)
        await prisma.ad.deleteMany({ where: { jobId } });

        await prisma.ad.createMany({
            data: parsedAdsResult.ads.map((ad, index) => ({
                jobId,
                adNumber: index + 1,
                title: ad.angle || ad.headline || `Ad ${index + 1}`,
                sourceBlock: JSON.stringify(ad, null, 2),
                editedPrompt: String(ad.visualPrompt || "").trim(),
                status: "ready",
            })),
        });

        await prisma.job.update({
            where: { id: jobId },
            data: {
                status: "success",
                rawText,
                claudeOutput: `${claudeOutput || ""}

__CLAUDE_PARSE_DIAGNOSTICS__
${diagJson}
__END_CLAUDE_PARSE_DIAGNOSTICS__`,
                kieResult: null,
            },
        });

        redirect(`/jobs/${jobId}`);
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        await prisma.job.update({
            where: { id: jobId },
            data: {
                status: "error",
                claudeOutput: JSON.stringify(
                    { stage: "scrape_and_generate_ads", error: message },
                    null,
                    2
                ),
            },
        });
        redirect(`/jobs/${jobId}`);
    }
}

async function saveAdPromptAndReferences(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();
    const editedPrompt = formData.get("editedPrompt")?.toString() || "";

    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    await prisma.ad.update({
        where: { id: adId },
        data: { editedPrompt },
    });

    redirect(`/jobs/${jobId}`);
}

async function generateAdImages(formData: FormData) {
    "use server";

    const jobId = formData.get("jobId")?.toString();
    const adId = formData.get("adId")?.toString();

    if (!jobId || !adId) throw new Error("Missing jobId or adId");

    const ad = await prisma.ad.findUnique({
        where: { id: adId },
    });

    if (!ad) throw new Error("Ad not found");

    const prompt = (ad.editedPrompt || ad.sourceBlock || "").trim();
    if (!prompt) throw new Error("No prompt available");

    const referenceAssets = await prisma.referenceAsset.findMany({
        where: {
            jobId,
            OR: [{ adId: null }, { adId }],
        },
        orderBy: {
            createdAt: "asc",
        },
    });

    const referenceImages = referenceAssets.map((asset) => asset.filePath);

    await prisma.ad.update({
        where: { id: adId },
        data: { status: "generating_images" },
    });

    try {
        const result = await generateImageWithKie(prompt, referenceImages);
        const urls = extractImageUrlsFromResult(result);

        await prisma.image.deleteMany({
            where: { adId },
        });

        if (urls.length > 0) {
            await prisma.image.createMany({
                data: urls.map((url) => ({
                    adId,
                    url,
                    prompt,
                })),
            });
        }

        await prisma.ad.update({
            where: { id: adId },
            data: {
                status: "images_generated",
                kieResult: JSON.stringify(result, null, 2),
            },
        });
    } catch (error) {
        const message = error instanceof Error ? error.message : String(error);

        await prisma.ad.update({
            where: { id: adId },
            data: {
                status: "kie_error",
                kieResult: `Kie generation failed:\n\n${message}`,
            },
        });
    }

    const refreshed = await prisma.ad.findUnique({
        where: { id: adId },
    });

    redirect(`/jobs/${jobId}`);
}

function extractLatestClaudeDiagnostics(claudeOutput: string | null) {
    const text = claudeOutput || "";
    const startMarker = "__CLAUDE_PARSE_DIAGNOSTICS__";
    const endMarker = "__END_CLAUDE_PARSE_DIAGNOSTICS__";
    const start = text.lastIndexOf(startMarker);
    if (start === -1) return null;
    const afterStart = start + startMarker.length;
    const end = text.indexOf(endMarker, afterStart);
    if (end === -1) return null;
    const jsonText = text.slice(afterStart, end).trim();
    const parsed = tryParseJson(jsonText);
    return parsed && typeof parsed === "object" ? parsed : null;
}

